diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..5ed3426b57fb 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2029,8 +2029,25 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     // C-(C2-X) --> X+(C-C2)
     if (match(Op1, m_Sub(m_ImmConstant(C2), m_Value(X))))
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
+
+    // C - (sub nuw C, Y) -> Y
+    Value *Y;
+    if (match(Op1, m_NUWSub(m_ImmConstant(C2), m_Value(Y))) && C == C2)
+      return replaceInstUsesWith(I, Y);
   }

+  // C1 - (sub nuw C2, Y) -> add Y, (C1 - C2)
+  const APInt *C1, *C2;
+  Value *InnerY;
+  if (match(Op0, m_APInt(C1)) &&
+      match(Op1, m_NUWSub(m_APInt(C2), m_Value(InnerY)))) {
+    APInt Offset = *C1 - *C2;
+    Value *NewAdd = Builder.CreateAdd(InnerY, ConstantInt::get(I.getType(), Offset));
+    return replaceInstUsesWith(I, NewAdd);
+  }
+
+  const APInt *Op0C;
+
   const APInt *Op0C;
   if (match(Op0, m_APInt(Op0C)) && Op0C->isMask()) {
     // Turn this into a xor if LHS is 2^n-1 and the remaining bits are known
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index c3dabc2d4a07..57fc2778be11 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1937,6 +1937,26 @@ Instruction *InstCombinerImpl::visitAnd(BinaryOperator &I) {
         return BinaryOperator::CreateXor(NewAnd, Op1);
       }
     }
+    // If we are masking the result of a nuw subtraction, we can distribute the
+    // mask as long as the mask is a shifted mask (contiguous ones).
+    // (sub nuw C2, X) & Mask --> sub nuw (C2 & Mask), (X & Mask)
+    // because the subtraction cannot borrow across the cleared low bits.
+    {
+      const APInt *C2;
+      Value *X;
+      if (match(Op0, m_NUWSub(m_APInt(C2), m_Value(X))) &&
+          C->isShiftedMask()) {
+        // Compute masked constants.
+        APInt MaskedC2 = *C2 & *C;
+        // Create X & Mask
+        Value *MaskedX = Builder.CreateAnd(X, Op1, X->getName() + ".masked");
+        // Create (C2 & Mask) - (X & Mask)
+        Constant *NewC = ConstantInt::get(Ty, MaskedC2);
+        Value *NewSub = Builder.CreateNUWSub(NewC, MaskedX);
+        return replaceInstUsesWith(I, NewSub);
+      }
+    }
+

     // ((C1 OP zext(X)) & C2) -> zext((C1 OP X) & C2) if C2 fits in the
     // bitwidth of X and OP behaves well when given trunc(C1) and X.

